DROP TABLE IF EXISTS J09B_temp;
CREATE TABLE J09B_temp AS
  SELECT *
  FROM decision_talbe
  WHERE TOUR LIKE 'J09B%';
ALTER TABLE J09B_temp ADD COLUMN ENTSCHEIDUNG TEXT;

UPDATE J09B_temp AS t
SET ENTSCHEIDUNG = CASE
    WHEN (
      SELECT COUNT(DISTINCT EQUNR)
      FROM J09B_temp AS t2
      WHERE t2.HAUS = t.HAUS
    ) < 3 THEN 'KSA'
    ELSE 'EVU'
END;

UPDATE J09B_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 = 0;

UPDATE J09B_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 = 0;
